class Solution:
    def groupStrings(self, words):
        def mask_of(w):
            m = 0
            for ch in w:
                m |= 1 << (ord(ch) - 97)
            return m
        masks = [mask_of(w) for w in words]
        distinct = sorted(set(masks))
        def connected(m1, m2):
            if m1 == m2:
                return True
            diff = bin(m1 ^ m2).count('1')
            if diff == 1:
                return True
            if diff == 2 and bin(m1).count('1') == bin(m2).count('1'):
                return True
            return False
        parent = {m: m for m in distinct}
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        n = len(distinct)
        for i in range(n):
            for j in range(i + 1, n):
                if connected(distinct[i], distinct[j]):
                    union(distinct[i], distinct[j])
        count = {}
        for m in masks:
            r = find(m)
            count[r] = count.get(r, 0) + 1
        return [len(count), max(count.values())]

