class Solution:
    def groupStrings(self, words):
        def mask_of(w):
            m = 0
            for ch in w:
                m |= 1 << (ord(ch) - 97)
            return m
        masks = []
        present = set()
        for w in words:
            m = mask_of(w)
            masks.append(m)
            present.add(m)
        parent = {}
        def find(x):
            parent.setdefault(x, x)
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        for m in present:
            find(m)
            for b in range(26):
                bit = 1 << b
                if m & bit:
                    neighbor = m ^ bit
                    if neighbor in present:
                        union(m, neighbor)
                    union(m, ('r', neighbor))
                else:
                    neighbor = m | bit
                    if neighbor in present:
                        union(m, neighbor)
        count = {}
        for m in masks:
            r = find(m)
            count[r] = count.get(r, 0) + 1
        return [len(count), max(count.values())]

