var groupStrings = function(words) {
    const present = new Set();
    const masks = [];
    for (const w of words) {
        let m = 0;
        for (const ch of w) {
            m |= 1 << (ch.charCodeAt(0) - 97);
        }
        masks.push(m);
        present.add(m);
    }
    const parent = new Map();
    function find(x) {
        if (!parent.has(x)) parent.set(x, x);
        let root = x;
        while (parent.get(root) !== root) root = parent.get(root);
        let cur = x;
        while (parent.get(cur) !== root) {
            const next = parent.get(cur);
            parent.set(cur, root);
            cur = next;
        }
        return root;
    }
    function union(a, b) {
        const ra = find(a), rb = find(b);
        if (ra !== rb) parent.set(ra, rb);
    }
    for (const m of present) {
        find('m' + m);
        for (let b = 0; b < 26; b++) {
            const bit = 1 << b;
            if (m & bit) {
                const neighbor = m ^ bit;
                if (present.has(neighbor)) union('m' + m, 'm' + neighbor);
                union('m' + m, 'r' + neighbor);
            } else {
                const neighbor = m | bit;
                if (present.has(neighbor)) union('m' + m, 'm' + neighbor);
            }
        }
    }
    const count = new Map();
    for (const m of masks) {
        const r = find('m' + m);
        count.set(r, (count.get(r) || 0) + 1);
    }
    let maxSize = 0;
    for (const v of count.values()) maxSize = Math.max(maxSize, v);
    return [count.size, maxSize];
};
